import { Component, OnInit, OnChanges, SimpleChanges, OnDestroy, input, model, output, inject } from '@angular/core';
import { MainService } from '../../services/main.service';

@Component({
    selector: 'zdc-main-drawer-modal-wrapper',
    templateUrl: './drawer-modal-wrapper.component.html',
    styleUrls: ['./drawer-modal-wrapper.component.scss'],
    standalone: false
})
export class DrawerModalWrapperComponent implements OnInit, OnChanges, OnDestroy {
  // private apiService = inject(ApiService);

  private mainService = inject(MainService);
  private apiService = this.mainService.getApiService();

  visible = model(false);

  readonly bar = input(false);
  readonly nzDrawerheight = input('auto');

  readonly nzModalWidth = input('500px');
  readonly showCloseButton = input<boolean>(true);
  readonly autoFocus = input<'ok' | 'cancel' | 'auto' | null>(null);

  readonly drawerClassName = input<string>('');

  /** Triggers the onClose event when the device's back button is pressed on an Android mobile device. */
  readonly closeOnBackPress = input(false);

  readonly onClose = output();

  isMobile = false;

  /** Inserted by Angular inject() migration for backwards compatibility */
  constructor(...args: unknown[]);

  constructor() { }

  ngOnInit(): void {
    this._findIsMobile();
  }

  _findIsMobile(): void {

    this.isMobile = !this.apiService.isWeb();
  }

  ngOnChanges(changes: SimpleChanges): void {

    if (this.closeOnBackPress()) {
      // @ts-ignore
      if (changes.visible.currentValue)
        this._addBackButtonStack();
      else this._removeBackButtonStack();
    }
  }

  /* Back button stack handler */
  // @ts-ignore
  private backButtonStackName: string = null;

  private _addBackButtonStack(): void {

    this.backButtonStackName = Math.random().toString(36).slice(2, 18) + Date.now() + Math.random().toString(36).slice(2, 18);

    this.apiService.backButtonStack.add(this.backButtonStackName, () => {
      this._removeBackButtonStack();
      this.onClose.emit();
    });
  }

  private _removeBackButtonStack(): void {

    if (!this.backButtonStackName) return;

    this.apiService.backButtonStack.remove(this.backButtonStackName);

    // @ts-ignore
    this.backButtonStackName = null;
  }
  /* // Back button stack handler */

  ngOnDestroy(): void {
    this._removeBackButtonStack();
  }
}
